#include<bits/stdc++.h>
//#include <conio.h>

using namespace std;
bool v[15][15][15][15][4][4];
char c[15][15];
int n = 10, m = 10;
int fd = 0, fx, fy, cd = 0, cx, cy;
int dy[4] = {0, 1, 0, -1};
int dx[4] = {-1, 0, 1, 0};
bool jud (int d, int x, int y) {
	int mx = dx[d] + x;
	int my = dy[d] + y;
	if (c[mx][my] == '*' || mx > n || mx <= 0 || my <= 0 || my > m) {
		return 0;
	} else {
		return 1;
	}
}
int main() {
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j <= n; j++) {
			cin >> c[i][j];
			if (c[i][j] == 'F') {
				fx = i;
				fy = j;
			}
			if (c[i][j] == 'C') {
				cx = i;
				cy = j;
			}
		}
	}
	int ans = 0;

	while (!v[fx][fy][cx][cy][fd][cd]) {
		if (fx == cx && cy == fy) {
			cout << ans;
			return 0;
		}
		v[fx][fy][cx][cy][fd][cd] = 1;
		if (jud(fd, fx, fy)) {
			c[fx][fy] = '.';
			fx = dx[fd] + fx;
			fy = dy[fd] + fy;
			c[fx][fy] = 'F';
		} else {
			fd++;
			fd %= 4;
		}
		if (jud(cd, cx, cy)) {
			c[cx][cy] = '.';
			cx = dx[cd] + cx;
			cy = dy[cd] + cy;
			c[cx][cy] = 'C';
		} else {
			cd++;
			cd %= 4;
		}
		ans++;
		/*system("cls");

		for (int i = 1; i <= n; i++) {
			for (int j = 1; j <= n; j++) {
				cout << c[i][j];
			}
			cout << "\n";
		}
		for (int i = 1; i <= 1000000; i++) cout << "";*/
	}
	cout << 0;
	return 0;
}
